import pandas as pd

# Load the data
examination_df = pd.read_csv('Examination.csv')
laboratory_df = pd.read_csv('Laboratory.csv')

# Clean and process RF column in Laboratory table
def clean_rf(rf_value):
    if pd.isna(rf_value):
        return None
    rf_str = str(rf_value).strip()
    if rf_str.startswith('<'):
        try:
            return float(rf_str[1:])
        except ValueError:
            return None
    else:
        try:
            return float(rf_str)
        except ValueError:
            return None

laboratory_df['RF_numeric'] = laboratory_df['RF'].apply(clean_rf)

# Filter Laboratory for normal RF (RF < 20 and not null)
normal_rf_patients = laboratory_df[
    (laboratory_df['RF_numeric'].notna()) &
    (laboratory_df['RF_numeric'] < 20)
]['ID'].unique()

# Filter Examination for patients without thrombosis (Thrombosis == 0)
no_thrombosis_patients = examination_df[
    examination_df['Thrombosis'] == 0
]['ID'].unique()

# Find intersection: patients with normal RF and no thrombosis
common_patients = set(normal_rf_patients).intersection(set(no_thrombosis_patients))

result = len(common_patients)
print(result)

